const elasticsearch = require('elasticsearch');

const client = new elasticsearch.Client({
  host: 'localhost:9200',
  log: 'trace'
});

function buildQuery(userQuery, script){
  return {
    query: {
      bool: {
        must: {
          match: userQuery
        },
        script_score : {
          script : {
            source: script
          }
        }
      }
    }
  };
}

